import org.apache.commons.csv.CSVFormat;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

import java.lang.reflect.Field;

public class CSVFormatTest {

    private CSVFormat csvFormat;

    @BeforeEach
    public void setUp() {
        csvFormat = CSVFormat.DEFAULT;
    }

    @Test
    public void testIsCommentMarkerSet_WhenCommentMarkerIsNull() throws Exception {
        // commentMarker is private final, create a new instance with null commentMarker using reflection
        CSVFormat format = createCSVFormatWithCommentMarker(null);
        assertFalse(format.isCommentMarkerSet());
    }

    @Test
    public void testIsCommentMarkerSet_WhenCommentMarkerIsSet() throws Exception {
        CSVFormat format = createCSVFormatWithCommentMarker('#');
        assertTrue(format.isCommentMarkerSet());
    }

    private CSVFormat createCSVFormatWithCommentMarker(Character commentMarker) throws Exception {
        // Use reflection to create a new CSVFormat instance with the given commentMarker
        // The constructor signature is:
        // CSVFormat(char delimiter, Character quoteChar, QuoteMode quoteMode, Character commentStart,
        //           Character escape, boolean ignoreSurroundingSpaces, boolean ignoreEmptyLines,
        //           String recordSeparator, String nullString, Object[] headerComments,
        //           String[] header, boolean skipHeaderRecord, boolean allowMissingColumnNames,
        //           boolean ignoreHeaderCase, boolean trim, boolean trailingDelimiter, boolean autoFlush)

        Class<?> clazz = CSVFormat.class;
        java.lang.reflect.Constructor<?> constructor = clazz.getDeclaredConstructor(
                char.class, Character.class, Class.forName("org.apache.commons.csv.QuoteMode"), Character.class,
                Character.class, boolean.class, boolean.class, String.class, String.class, Object[].class,
                String[].class, boolean.class, boolean.class, boolean.class, boolean.class, boolean.class, boolean.class);
        constructor.setAccessible(true);

        // Use QuoteMode.ALL_NON_NULL for the quoteMode parameter for simplicity
        Class<?> quoteModeClass = Class.forName("org.apache.commons.csv.QuoteMode");
        Object quoteModeAllNonNull = java.lang.Enum.valueOf((Class<Enum>) quoteModeClass, "ALL_NON_NULL");

        return (CSVFormat) constructor.newInstance(
                ',', // delimiter
                '"', // quoteChar
                quoteModeAllNonNull,
                commentMarker,
                null,
                false,
                true,
                "\r\n",
                null,
                null,
                null,
                false,
                false,
                false,
                false,
                false,
                false);
    }
}
